rule.query:
{
  "selection_base64": {
    "CommandLine|contains": "base64 "
  },
  "selection_exec": [
    {
      "CommandLine|contains": [
        "| bash ",
        "| sh ",
        "|bash ",
        "|sh "
      ]
    },
    {
      "CommandLine|endswith": [
        " |sh",
        "| bash",
        "| sh",
        "|bash"
      ]
    }
  ],
  "condition": "all of selection_*"
}
